import logging
from dataclasses import dataclass
from typing import Dict
import unittest

# Configure logging for production observability
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger(__name__)

@dataclass
class InventoryItem:
    """Represents an item in the inventory system."""
    id: str
    name: str
    quantity: int

class InventoryManager:
    """Manages inventory operations with validation and low-stock alerts."""

    LOW_STOCK_THRESHOLD = 5

    def __init__(self) -> None:
        self._items: Dict[str, InventoryItem] = {}

    def _validate_quantity(self, quantity: int) -> None:
        """Ensures quantity is non-negative."""
        if quantity < 0:
            raise ValueError("Quantity cannot be negative.")

    def add_item(self, item: InventoryItem) -> None:
        """Adds a new item to the inventory."""
        if item.id in self._items:
            raise ValueError(f"Item with ID '{item.id}' already exists.")
        self._validate_quantity(item.quantity)
        self._items[item.id] = item
        logger.info(f"Added item: {item.name} (ID: {item.id})")

    def update_stock(self, item_id: str, delta: int) -> None:
        """Updates stock levels and triggers alerts if below threshold."""
        if item_id not in self._items:
            raise KeyError(f"Item with ID '{item_id}' not found.")

        item = self._items[item_id]
        new_quantity = item.quantity + delta

        self._validate_quantity(new_quantity)

        item.quantity = new_quantity
        if item.quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"LOW STOCK ALERT: {item.name} (ID: {item_id}) is at {item.quantity}")

class TestInventoryManager(unittest.TestCase):
    """Unit tests for InventoryManager."""

    def setUp(self) -> None:
        self.manager = InventoryManager()
        self.item = InventoryItem("A1", "Widget", 10)

    def test_add_item(self) -> None:
        self.manager.add_item(self.item)
        self.assertEqual(self.manager._items["A1"].quantity, 10)

    def test_duplicate_id_raises_error(self) -> None:
        self.manager.add_item(self.item)
        with self.assertRaises(ValueError):
            self.manager.add_item(self.item)

    def test_update_stock_success(self) -> None:
        self.manager.add_item(self.item)
        self.manager.update_stock("A1", -2)
        self.assertEqual(self.manager._items["A1"].quantity, 8)

    def test_negative_stock_raises_error(self) -> None:
        self.manager.add_item(self.item)
        with self.assertRaises(ValueError):
            self.manager.update_stock("A1", -15)

    def test_low_stock_alert(self) -> None:
        self.manager.add_item(self.item)
        with self.assertLogs(level='WARNING') as cm:
            self.manager.update_stock("A1", -7)
            self.assertTrue(any("LOW STOCK ALERT" in output for output in cm.output))

    def test_non_existent_item(self) -> None:
        with self.assertRaises(KeyError):
            self.manager.update_stock("INVALID", 1)

if __name__ == "__main__":
    unittest.main()
